#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float corr = uTexSize.xy*texsize_noise_hq.zw * 0.05;
vec2 uv1 = vec2(vUv.x-0.5,vUv.y-0.5);

vec2 uv3 = uv1;
float dist = 100 ;

uv3 = dist * uv1;

float zu = lum(texture(sampler_noise_lq,vUv)) ;
float ky = clamp01(-uv3.y/100+zu/4*cos(16*zu)+.23);

float k1 = uv3.x;

k1 = k1 - sign (k1)*24; //Verdoppelung
k1 = k1 - sign (k1)*9; //Verdoppelung

int n = 1 ;
float delta = .1;
while (n <= 5)
{
  k1 += (k1-12*n*sign(k1))*ky*ky;
  //Mult. mit n steuert "Breitenwuchs"
  ky = clamp01(ky - delta);
  //delta ist vertikaler Verzweig. abstand
  n++;
}

k1 = clamp(k1,-1.6,1.6);

tree = vec3 (.1,0,0) * (cos(k1));


ret = GetPixel(fract(vUv))*.5 +tree;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

y0 = .1;
vUv -= 0.5;
vUv *= uAspect.xy;
vUv.x = vUv.x / (1+0*y0*vUv.y); //Perspektive
ret1 = 0; anz = 3; n = 1;

//Wasser
z1 = clamp(1/(vUv.y-y0),-0,200);
rs = vec2(vUv.x *z1+ uTime/1 , z1)/44;
water = lum(texture(sampler_noise_lq,rs))-.5;
water *= clamp01(16*(vUv.y - y0));
float refl = (water)/16;

//Wolken
uv4 = vec2 (vUv.x+q31,abs(vUv.y-y0)-abs(q31/2)); //pos. Sonne
z2 = clamp(1/(abs(vUv.y-y0)),-0,200);
uv4.y += refl*0;
rs = vec2(uv4.x * z2, z2)/16 +refl;
vec3 clouds = lum(texture(sampler_noise_hq,rs+.0*uTime));
clouds *= clamp01(.6-2*(vUv.y-y0)) * 0.5/(.04+length(uv4)) ;
clouds *= vec3 (1,.6, q32/z2);

//Berge
uv5 = vUv+ vec2(q28/4,0) + refl;
horiz = abs(uv5.y-y0)
*(1+texture(sampler_noise_lq,vec2(uv5.x*8,uv5.y*4)).r)
*(1+texture(sampler_noise_hq,uv5.x/4).x);
horiz = clamp01(1-q30*horiz);

for (n=1;n<=anz;n++) {
    dist = .8-.4*fract(1.0*n/anz-.2);

    uv2.y = vUv.y;
    uv2.x = vUv.x + n*.65;
    uv2 = 1.5*dist*(uv2)-y0-.4; //Blickpunkt vert.

    uv3 = fract(uv2+q28*vec2(1,0.0)) ;
    neu = texture(sampler_main, uv3);
    ret1 = ret1 + neu;
//n++;
}


ret = (.1*(.5+water) + .2/q30) *vec3 (0,.5,.6)
+ clamp01(clouds*(1-4*horiz))
+ horiz*vec3(1,1,1)*.06;
ret *= clamp01(1- ret1.r*8) ;

  fragColor = ret;
}
